import Link from "next/link";
import styles from "styles/Wireframe.module.scss";

interface WireframeLinkProps {
  id: string;
  text: string;
  href: string;
  align: "left" | "right";
  style?: React.CSSProperties;
}
export const WireframeLink = ({
  id,
  text,
  href,
  align,
  style,
}: WireframeLinkProps) => {
  return (
    <div
      className={`${styles[`link-${id}`]} ${styles.linkAnchor} ${styles[`align-${align}`]}`}
      style={style}
    >
      <Link href={href} className={styles.link}>
        {text}
      </Link>
    </div>
  );
};

